from flask import Flask, redirect, url_for
from flask_oidc import OpenIDConnect

app = Flask(__name__)
oidc = OpenIDConnect(app)

# Configure OIDC with your OpenID Connect provider information
oidc.oidc_provider('google', client_id='YOUR_CLIENT_ID', client_secret='YOUR_CLIENT_SECRET')
oidc.oidc_discovery('https://accounts.google.com/.well-known/openid-configuration')

@app.route('/login')
def login():
    scope = ['openid']
    return oidc.auth_redirect(scope=scope, response_type='id_token')

@app.route('/callback', methods=['GET'])
@oidc.oidc_auth_handler
def callback():
    # Handle authentication here and perform any actions you need
    return 'Authenticated successfully!'

